SELECT count(*) FROM movie_companies, company_name, company_type, title, kind_type, cast_info, name WHERE movie_companies.company_id = company_name.id AND movie_companies.company_type_id = company_type.id AND movie_companies.movie_id = title.id AND title.kind_id = kind_type.id AND cast_info.movie_id = title.id AND cast_info.person_id = name.id;